mapper.select:
SELECT u.id AS userId, u.nickname, u.email, u.created_at AS registeredAt, u.coin_balance AS coinBalance, COALESCE(SUM(er.amount), 0) AS totalEarnings, COALESCE(SUM(CASE WHEN er.status = 0 THEN er.amount ELSE 0 END), 0) AS unsettledEarnings FROM u_user u LEFT JOIN u_earnings_record er ON er.user_id = u.id AND er.is_deleted = 0 WHERE u.is_deleted = 0
AND u.id = #{userId}
AND u.nickname LIKE CONCAT('%', #{nickname}, '%')
AND u.email LIKE CONCAT('%', #{email}, '%')
GROUP BY u.id, u.nickname, u.email, u.created_at, u.coin_balance ORDER BY u.id DESC LIMIT #{offset}, #{size}
